// Input from previous node
const input = items[0].json.output;

try {
  // Parse the JSON string into an object
  const parsed = JSON.parse(input);

  // Return parsed values as separate fields
  return [
    {
      json: {
        subject: parsed.subject,
        body_plain: parsed.body_plain,
        body_html: parsed.body_html
      }
    }
  ];
} catch (error) {
  // Handle malformed JSON
  return [
    {
      json: {
        error: 'Invalid JSON format in input',
        details: error.message
      }
    }
  ];
}

// Loop through all incoming items
for (const item of $input.all()) {

  // Handle flexible field names from input
  const name = item.json.recipient_name || item.json.Name || 'there';
  const company = item.json.recipient_company || item.json.Company || 'your company';
  const pain = item.json["Pain Point"] || 'scaling operations effectively';

  // Adapt field mappings for your given input structure
  const subject = item.json.subject || `Solution for ${company}`;
  const plain = item.json.body_plain || '';
  const html = item.json.body_html || '';
  const recipient = item.json.recipient_email || item.json["Email id"] || '';

  // Function: Extract relevant sections from plain text
  const extractSection = (keywords) => {
    if (!plain) return 'Details will be shared during our discovery call.';

    const lines = plain.split('\n');
    const sectionLines = [];
    let capturing = false;
    let captureCount = 0;

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i].trim();
      const lowerLine = line.toLowerCase();

      if (keywords.some(kw => lowerLine.includes(kw.toLowerCase()))) capturing = true;
      if (capturing && line) {
        sectionLines.push(line);
        captureCount++;
        if (captureCount > 8 || lowerLine.includes('best regards') || lowerLine.includes('sincerely')) break;
      }
    }

    return sectionLines.length > 0 
      ? sectionLines.join('<br>') 
      : 'Customized approach based on your specific needs.';
  };

  // Construct final professional HTML email
  item.json.final_html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${subject}</title>
<style>
  body { margin: 0; padding: 20px; background: #f7f9fc; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif; }
  .email-container { max-width: 600px; margin: 0 auto; background: white; border-radius: 16px; overflow: hidden; box-shadow: 0 10px 40px rgba(0,0,0,0.08); }
  .header { background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; padding: 40px 32px; text-align: center; }
  .header h1 { margin: 0 0 12px; font-size: 28px; font-weight: 700; line-height: 1.2; }
  .section { padding: 28px 32px; margin: 0; border-bottom: 1px solid #f1f5f9; }
  .section:last-of-type { border-bottom: none; }
  .challenge { background: #fffbeb; border-left: 4px solid #f59e0b; }
  .solution { background: #f0fdf4; border-left: 4px solid #10b981; }
  .timeline { background: #eff6ff; border-left: 4px solid #3b82f6; }
  .benefits { background: #fdf2f8; border-left: 4px solid #ec4899; }
  .cta { background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; text-align: center; padding: 40px 32px; }
  .cta a { display: inline-block; background: white; color: #667eea; padding: 14px 32px; border-radius: 8px; text-decoration: none; font-weight: 600; font-size: 16px; margin-top: 16px; transition: all 0.3s ease; }
  .cta a:hover { transform: translateY(-2px); box-shadow: 0 6px 16px rgba(0,0,0,0.2); }
  .footer { background: #f8fafc; color: #64748b; padding: 24px 32px; text-align: center; font-size: 14px; line-height: 1.6; }
  .footer a { color: #667eea; text-decoration: none; }
  .footer a:hover { text-decoration: underline; }
</style>
</head>
<body>
<div class="email-container">
  <div class="header">
    <h1>Personalized Solution for ${company}</h1>
    <p>Hi ${name}, here's a tailored approach to address your specific challenge.</p>
  </div>

  <div class="section challenge">
    <h2>Your Current Challenge</h2>
    <p><strong>${pain}</strong></p>
    <p>We recognize the operational impact this may cause, and we’ve designed a custom plan to resolve it efficiently.</p>
  </div>

  <div class="section solution">
    <h2>Proposed Solution Framework</h2>
    <p>${extractSection(['solution', 'approach', 'framework', 'phase', 'implementation'])}</p>
  </div>

  <div class="section timeline">
    <h2>Implementation Timeline</h2>
    <p>${extractSection(['timeline', 'week', 'phase', 'schedule'])}</p>
  </div>

  <div class="section benefits">
    <h2>Expected Benefits</h2>
    <p>${extractSection(['benefit', 'outcome', 'result', 'improve', 'increase'])}</p>
  </div>

  <div class="cta">
    <h2>Let’s Discuss This Further</h2>
    <p>Would you be open to a brief 15–20 minute discovery call to tailor this plan to ${company}?</p>
    <a href="https://calendly.com/your-team/15min" target="_blank">Schedule Your Call</a>
  </div>

  <div class="footer">
    <p><strong>Best regards,</strong><br>Your Automation Partner</p>
    <p><a href="mailto:solutions@youragency.com">solutions@youragency.com</a> | (123) 456-7890</p>
  </div>
</div>
</body>
</html>`;

  // Ensure correct mapping for output
  item.json.final_subject = subject;
  item.json.final_body_plain = plain;
  item.json.final_recipient = recipient;
}

// Return all processed items
return $input.all();
